  <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
    <h3 style="font-size:20px;font-weight:800;">Bitácora</h3>
    <div style="display:flex;gap:12px;"><button onclick="copiarHistorial()" style="background:none;border:none;color:var(--accent);font-weight:700;cursor:pointer;">COPIAR</button><button onclick="toggleNotas()" style="background:var(--ink2);border:none;border-radius:8px;width:40px;height:40px;display:flex;align-items:center;justify-content:center;cursor:pointer;"><svg viewBox="0 0 24 24" width="20" height="20" stroke="currentColor" fill="none"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div>
  </div>
